class Solution:
    def validSequence(self, word1: str, word2: str) -> List[int]:
        n, m = len(word1), len(word2)
        if m > n:
            return []

        # Precompute left array: left[i] = minimal index in word1 such that word1[left[i]] matches word2[i] and left[i] > left[i-1]
        left = [0] * m
        j = 0
        for i in range(m):
            while j < n and word1[j] != word2[i]:
                j += 1
            if j >= n:
                left[i] = -1
            else:
                left[i] = j
                j += 1

        # Precompute right array: right[i] = maximal index in word1 such that word1[right[i]] matches word2[i] and right[i] < right[i+1]
        right = [0] * m
        j = n - 1
        for i in range(m-1, -1, -1):
            while j >= 0 and word1[j] != word2[i]:
                j -= 1
            if j < 0:
                right[i] = -1
            else:
                right[i] = j
                j -= 1

        # Check if exact match exists
        if left[-1] != -1:
            return list(range(m))

        # Check if one substitution is possible
        best = None
        for k in range(m):
            # Check if we can substitute word1[pos] to word2[k]
            # Need left[k-1] < pos < right[k+1] (if they exist)
            left_bound = left[k-1] if k > 0 else -1
            right_bound = right[k+1] if k < m-1 else n

            # Find the smallest pos in [left_bound+1, right_bound-1] where word1[pos] != word2[k]
            low = left_bound + 1
            high = right_bound - 1
            if low > high:
                continue

            # The smallest pos is low (since we want lex smallest sequence)
            pos = low
            if pos < n and (k == 0 or pos > left[k-1]) and (k == m-1 or pos < right[k+1]):
                # Construct the sequence
                seq = []
                # First k-1 elements from left
                for i in range(k):
                    seq.append(left[i])
                seq.append(pos)
                # Remaining elements from right shifted
                for i in range(k+1, m):
                    seq.append(right[i] + (i - (k+1)))
                # Verify the sequence is valid
                valid = True
                for i in range(m):
                    if i == k:
                        continue
                    expected = word2[i]
                    actual = word1[seq[i]]
                    if actual != expected:
                        valid = False
                        break
                if valid:
                    if best is None or seq < best:
                        best = seq

        return best if best is not None else []
